import React, { createContext, useContext, useState, useEffect } from 'react';
import axios from 'axios';

/**
 * Authentication Context for managing user authentication state
 * Provides authentication methods and user data throughout the app
 */
const AuthContext = createContext();

/**
 * Custom hook to use authentication context
 * @returns {Object} Authentication context value
 */
export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

/**
 * AuthProvider component that wraps the app and provides authentication context
 * @param {Object} children - Child components
 */
export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Configure axios defaults
  useEffect(() => {
    if (token) {
      axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    } else {
      delete axios.defaults.headers.common['Authorization'];
    }
  }, [token]);

  // Configure axios base URL and interceptors
  useEffect(() => {
    // Prefer env var in production; otherwise use relative URL to flow through CRA proxy
    const envBaseUrl = process.env.REACT_APP_API_URL;
    const isLocalhost = typeof window !== 'undefined' && window.location.hostname === 'localhost';
    axios.defaults.baseURL = envBaseUrl || (isLocalhost ? '' : '');

    // Add request interceptor for logging
    axios.interceptors.request.use(
      (config) => {
        console.log('Making API request:', config.method?.toUpperCase(), config.url);
        return config;
      },
      (error) => {
        console.error('Request error:', error);
        return Promise.reject(error);
      }
    );

    // Add response interceptor for error handling
    axios.interceptors.response.use(
      (response) => {
        console.log('API response:', response.status, response.config.url);
        return response;
      },
      (error) => {
        console.error('API error:', error.response?.status, error.response?.data, error.config?.url);
        return Promise.reject(error);
      }
    );
  }, []);

  /**
   * Check if user is authenticated by verifying token
   */
  const checkAuth = async () => {
    if (!token) {
      setLoading(false);
      return;
    }

    try {
      console.log('Verifying token...');
      const response = await axios.get('/api/auth/verify-token');
      if (response.data.success) {
        setUser(response.data.data.user);
        console.log('Token verified for user:', response.data.data.user.name);
      } else {
        // Token is invalid, remove it
        console.log('Token verification failed, removing token');
        localStorage.removeItem('token');
        setToken(null);
        setUser(null);
      }
    } catch (error) {
      console.error('Auth verification failed:', error);
      // Token is invalid or expired, remove it
      localStorage.removeItem('token');
      setToken(null);
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  // Check authentication on component mount
  useEffect(() => {
    checkAuth();
  }, []);

  /**
   * Login user with email and password
   * @param {string} email - User's email
   * @param {string} password - User's password
   * @returns {Promise<Object>} Login response
   */
  const login = async (email, password) => {
    try {
      setError(null);
      setLoading(true);

      console.log('Attempting login for:', email);

      const response = await axios.post('/api/auth/login', {
        email,
        password
      });

      console.log('Login response:', response.data);

      if (response.data.success) {
        const { user: userData, token: authToken } = response.data.data;

        // Store token in localStorage
        localStorage.setItem('token', authToken);
        setToken(authToken);
        setUser(userData);

        // Set axios default header
        axios.defaults.headers.common['Authorization'] = `Bearer ${authToken}`;

        console.log('Login successful for user:', userData.name);
        return { success: true, user: userData };
      } else {
        throw new Error(response.data.message || 'Login failed');
      }
    } catch (error) {
      console.error('Login error details:', error);
      const errorMessage = error.response?.data?.message || error.message || 'Login failed';
      setError(errorMessage);
      return { success: false, error: errorMessage };
    } finally {
      setLoading(false);
    }
  };

  /**
   * Register new user
   * @param {Object} userData - User registration data
   * @returns {Promise<Object>} Registration response
   */
  const signup = async (userData) => {
    try {
      setError(null);
      setLoading(true);

      console.log('Attempting signup for:', userData.email);

      const response = await axios.post('/api/auth/signup', userData);

      console.log('Signup response:', response.data);

      if (response.data.success) {
        const { user: newUser, token: authToken } = response.data.data;

        // Store token in localStorage
        localStorage.setItem('token', authToken);
        setToken(authToken);
        setUser(newUser);

        // Set axios default header
        axios.defaults.headers.common['Authorization'] = `Bearer ${authToken}`;

        console.log('Signup successful for user:', newUser.name);
        return { success: true, user: newUser };
      } else {
        throw new Error(response.data.message || 'Registration failed');
      }
    } catch (error) {
      console.error('Signup error details:', error);
      const errorMessage = error.response?.data?.message || error.message || 'Registration failed';
      setError(errorMessage);
      return { success: false, error: errorMessage };
    } finally {
      setLoading(false);
    }
  };

  /**
   * Logout user and clear authentication data
   */
  const logout = async () => {
    try {
      // Call logout endpoint (optional, for server-side cleanup)
      if (token) {
        await axios.post('/api/auth/logout');
      }
    } catch (error) {
      console.error('Logout error:', error);
    } finally {
      // Clear local storage and state regardless of server response
      localStorage.removeItem('token');
      setToken(null);
      setUser(null);
      delete axios.defaults.headers.common['Authorization'];
    }
  };

  /**
   * Update user profile
   * @param {Object} updateData - Data to update
   * @returns {Promise<Object>} Update response
   */
  const updateProfile = async (updateData) => {
    try {
      setError(null);
      setLoading(true);

      const response = await axios.put('/api/auth/profile', updateData);

      if (response.data.success) {
        setUser(response.data.data.user);
        return { success: true, user: response.data.data.user };
      } else {
        throw new Error(response.data.message || 'Profile update failed');
      }
    } catch (error) {
      const errorMessage = error.response?.data?.message || error.message || 'Profile update failed';
      setError(errorMessage);
      return { success: false, error: errorMessage };
    } finally {
      setLoading(false);
    }
  };

  /**
   * Change user password
   * @param {string} currentPassword - Current password
   * @param {string} newPassword - New password
   * @returns {Promise<Object>} Change password response
   */
  const changePassword = async (currentPassword, newPassword) => {
    try {
      setError(null);
      setLoading(true);

      const response = await axios.post('/api/auth/change-password', {
        currentPassword,
        newPassword
      });

      if (response.data.success) {
        return { success: true };
      } else {
        throw new Error(response.data.message || 'Password change failed');
      }
    } catch (error) {
      const errorMessage = error.response?.data?.message || error.message || 'Password change failed';
      setError(errorMessage);
      return { success: false, error: errorMessage };
    } finally {
      setLoading(false);
    }
  };

  /**
   * Clear error message
   */
  const clearError = () => {
    setError(null);
  };

  /**
   * Check if user has specific role
   * @param {string|Array} roles - Role(s) to check
   * @returns {boolean} True if user has required role
   */
  const hasRole = (roles) => {
    if (!user) return false;

    if (Array.isArray(roles)) {
      return roles.includes(user.role);
    }

    return user.role === roles;
  };

  /**
   * Check if user is admin
   * @returns {boolean} True if user is admin
   */
  const isAdmin = () => {
    return hasRole('admin');
  };

  /**
   * Check if user is doctor
   * @returns {boolean} True if user is doctor
   */
  const isDoctor = () => {
    return hasRole('doctor');
  };

  /**
   * Check if user is patient
   * @returns {boolean} True if user is patient
   */
  const isPatient = () => {
    return hasRole('patient');
  };

  const value = {
    user,
    token,
    loading,
    error,
    login,
    signup,
    logout,
    updateProfile,
    changePassword,
    clearError,
    hasRole,
    isAdmin,
    isDoctor,
    isPatient,
    isAuthenticated: !!user
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};
